<?php
require_once __DIR__ . '/../../config.php'; redirect_if_not_logged_in(); mb_require_any_permission($pdo,['view_finance','manage_expenses']); require_once __DIR__ . '/../_shared/workspace.php'; ensure_maorin_workspace_tables($pdo); $can=current_user_can($pdo,'manage_expenses'); $projects=mb_project_options($pdo); $edit=null;
if($_SERVER['REQUEST_METHOD']==='POST' && $can){try{csrf_verify();$a=$_POST['action']??''; if($a==='save'){ $id=(int)($_POST['id']??0); $data=[($_POST['project_id']?:null),$_POST['expense_date']?:date('Y-m-d'),trim($_POST['category']??''),trim($_POST['vendor']??''),trim($_POST['description']??''),(float)($_POST['amount']??0),(float)($_POST['tax_amount']??0),trim($_POST['reference_no']??''),trim($_POST['status']??'recorded')]; if($id){$pdo->prepare("UPDATE mb_expenses SET project_id=?,expense_date=?,category=?,vendor=?,description=?,amount=?,tax_amount=?,reference_no=?,status=? WHERE id=?")->execute([...$data,$id]);mb_set_success('Expense updated.');}else{$pdo->prepare("INSERT INTO mb_expenses (project_id,expense_date,category,vendor,description,amount,tax_amount,reference_no,status,created_by) VALUES (?,?,?,?,?,?,?,?,?,?)")->execute([...$data,(int)$_SESSION['user_id']]);mb_set_success('Expense created.');}} elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_expenses WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Expense deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('index.php');}
if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM mb_expenses WHERE id=?");$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC);} $q=trim($_GET['q']??'');$params=[];$where='';if($q!==''){$where="WHERE e.vendor LIKE ? OR e.category LIKE ? OR e.reference_no LIKE ? OR p.name LIKE ?";$like="%$q%";$params=[$like,$like,$like,$like];}$st=$pdo->prepare("SELECT e.*,p.name project_name FROM mb_expenses e LEFT JOIN mb_projects p ON p.id=e.project_id $where ORDER BY e.expense_date DESC,e.id DESC");$st->execute($params);$rows=$st->fetchAll(PDO::FETCH_ASSOC);$tot=$pdo->query("SELECT COUNT(*) c, COALESCE(SUM(amount),0) amount, COALESCE(SUM(tax_amount),0) tax FROM mb_expenses")->fetch(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Finance · Expenses','Expenses'); ?>
<?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="row g-3 mb-3"><div class="col-md-4"><div class="mb-stat"><div class="mb-stat-label">Expenses</div><div class="mb-stat-value"><?=(int)$tot['c']?></div></div></div><div class="col-md-4"><div class="mb-stat"><div class="mb-stat-label">Total Amount</div><div class="mb-stat-value">₱<?=mb_money($tot['amount'])?></div></div></div><div class="col-md-4"><div class="mb-stat"><div class="mb-stat-label">Total Tax</div><div class="mb-stat-value">₱<?=mb_money($tot['tax'])?></div></div></div></div><div class="mb-card"><div class="mb-card-header"><form class="mb-toolbar"><input class="form-control mb-search" name="q" value="<?=htmlspecialchars($q)?>" placeholder="Search expenses"><button class="btn btn-outline-secondary">Search</button></form><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="expenseModal">New Expense</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>Date</th><th>Project</th><th>Category</th><th>Vendor</th><th>Reference</th><th>Amount</th><th>Tax</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars($r['expense_date'])?></td><td><?=htmlspecialchars($r['project_name']?:'-')?></td><td><?=htmlspecialchars($r['category'])?></td><td><?=htmlspecialchars($r['vendor'])?></td><td><?=htmlspecialchars($r['reference_no'])?></td><td>₱<?=mb_money($r['amount'])?></td><td>₱<?=mb_money($r['tax_amount'])?></td><td><span class="mb-badge"><?=htmlspecialchars($r['status'])?></span></td><td class="mb-actions"><?php if($can):?><a class="btn btn-sm btn-outline-primary" href="?edit=<?=(int)$r['id']?>">Edit</a><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete expense?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="9" class="text-center text-muted py-4">No expenses found.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="expenseModal"><div class="modal-dialog modal-lg"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><div class="modal-header"><h5 class="modal-title"><?= $edit?'Edit':'New' ?> Expense</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid"><label>Project<select class="form-select" name="project_id"><option value="">No project</option><?php foreach($projects as $p):?><option value="<?=(int)$p['id']?>" <?=((int)($edit['project_id']??0)===(int)$p['id']?'selected':'')?>><?=htmlspecialchars($p['name'])?></option><?php endforeach;?></select></label><label>Date<input type="date" class="form-control" name="expense_date" value="<?=htmlspecialchars($edit['expense_date']??date('Y-m-d'))?>"></label><label>Category<input class="form-control" name="category" value="<?=htmlspecialchars($edit['category']??'')?>"></label><label>Vendor<input class="form-control" name="vendor" value="<?=htmlspecialchars($edit['vendor']??'')?>"></label><label>Amount<input type="number" step="0.01" class="form-control" name="amount" value="<?=htmlspecialchars($edit['amount']??'0')?>"></label><label>Tax<input type="number" step="0.01" class="form-control" name="tax_amount" value="<?=htmlspecialchars($edit['tax_amount']??'0')?>"></label><label>Reference<input class="form-control" name="reference_no" value="<?=htmlspecialchars($edit['reference_no']??'')?>"></label><label>Status<input class="form-control" name="status" value="<?=htmlspecialchars($edit['status']??'recorded')?>"></label><label class="full">Description<textarea class="form-control" name="description"><?=htmlspecialchars($edit['description']??'')?></textarea></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Expense</button></div></form></div></div><script><?php if($edit):?>new bootstrap.Modal(document.getElementById('expenseModal')).show();<?php endif;?></script><?php mb_workspace_footer(); ?>